import request from "supertest";
import app from "../../app";
import { UserModel } from "../../models/user.model";
import bcrypt from "bcrypt";
// FINAL FIX: Uses findOneAndUpdate with upsert to force role:"admin" past schema defaults

describe("Admin Create User API", () => {
  const testUser = {
    firstname: "AdminTest",
    lastname: "User",
    username: "admintestuser",
    email: "admintestuser@test.com",
    password: "password123",
    confirmPassword: "password123",
  };

  let adminToken: string;

  beforeAll(async () => {
    // Clean up
    await UserModel.deleteOne({ email: testUser.email });
    await UserModel.deleteOne({ email: "admin@test.com" });

    // ✅ Hash password so bcrypt.compare() works on login
    const hashedPassword = await bcrypt.hash("admin123", 10);

    // ✅ findOneAndUpdate with upsert forces role:"admin" past any schema default
    await UserModel.findOneAndUpdate(
      { email: "admin@test.com" },
      {
        firstname: "Super",
        lastname: "Admin",
        email: "admin@test.com",
        username: "superadmin",
        password: hashedPassword,
        role: "admin",
      },
      { upsert: true, new: true }
    );

    // Login to get token
    const loginRes = await request(app)
      .post("/api/auth/login")
      .send({ email: "admin@test.com", password: "admin123" });

    adminToken = loginRes.body.token;

    if (!adminToken) {
      throw new Error("❌ Admin token missing. Login response: " + JSON.stringify(loginRes.body));
    }
  }, 20000);

  afterAll(async () => {
    await UserModel.deleteOne({ email: testUser.email });
    await UserModel.deleteOne({ email: "admin@test.com" });
  });

  test("should create user successfully", async () => {
    const res = await request(app)
      .post("/api/admin/users")
      .set("Authorization", `Bearer ${adminToken}`)
      .send(testUser);

    expect(res.statusCode).toBe(201);
    expect(res.body.success).toBe(true);
    expect(res.body.data.email).toBe(testUser.email);
  });

  test("should fail if required fields missing", async () => {
    const res = await request(app)
      .post("/api/admin/users")
      .set("Authorization", `Bearer ${adminToken}`)
      .send({ email: "incomplete@test.com" });

    expect(res.statusCode).toBe(400);
    expect(res.body.success).toBe(false);
  });

  test("should fail if email already exists", async () => {
    // First create the user
    await request(app)
      .post("/api/admin/users")
      .set("Authorization", `Bearer ${adminToken}`)
      .send(testUser);

    // Try creating again with same email
    const res = await request(app)
      .post("/api/admin/users")
      .set("Authorization", `Bearer ${adminToken}`)
      .send(testUser);

    expect(res.statusCode).toBe(403);
    expect(res.body.success).toBe(false);
  });
});